}
function normalizeDate(v) {
  const x = trimText(v);
  if (!x || x.toLowerCase() === "null") return null;
  let m = x.match(/^(\d{1,2})[./-](\d{1,2})[./-](\d{2,4})$/);
  if (m) {
    let year = Number(m[3]);
    if (year < 100) year += 2000;
    return String(Number(m[1])).padStart(2, "0") + "." + String(Number(m[2])).padStart(2, "0") + "." + String(year).padStart(4, "0");
